"""
T017 Implementation: GWAS Logistic Regression Wrapper
Executes PLINK2 logistic regression based on model configuration.
"""
import os
import sys
import subprocess
import yaml
import argparse
from pathlib import Path

def load_model_config(config_path: str) -> dict:
    """Load the model configuration generated by T046."""
    with open(config_path, 'r') as f:
        return yaml.safe_load(f)

def build_plink_command(config: dict, input_prefix: str, output_prefix: str) -> list:
    """
    Construct the PLINK2 command based on the strategy in the config.
    """
    strategy = config.get('strategy', 'Covariates')
    pheno_file = 'data/processed/phenotypes_cleaned.fam'
    
    # Determine covariate file
    if strategy == 'Covariates':
        covar_file = 'data/processed/phenotypes_cleaned.pheno'
        if not os.path.exists(covar_file):
            raise FileNotFoundError(f"Covariate file not found: {covar_file}")
    elif strategy == 'PCA':
        covar_file = 'data/processed/pruned_genotypes.eigenvec'
        if not os.path.exists(covar_file):
            raise FileNotFoundError(f"PCA file not found: {covar_file}")
    else:
        raise ValueError(f"Unknown strategy: {strategy}")

    cmd = [
        'plink2',
        '--bfile', input_prefix,
        '--pheno', pheno_file,
        '--family', '0',
        '--covar', covar_file,
        '--logistic', 'hide-covar',
        '--ci', '0.95',
        '--out', output_prefix
    ]
    return cmd

def main():
    parser = argparse.ArgumentParser(description="Execute GWAS Logistic Regression (T017)")
    parser.add_argument('--config', default='data/processed/model_config.yaml', help='Path to model config')
    parser.add_argument('--input', default='data/processed/pruned_genotypes', help='PLINK binary prefix')
    parser.add_argument('--output', default='data/interim/gwas_raw', help='Output prefix')
    args = parser.parse_args()

    print(f"Starting GWAS execution (T017)...")
    
    # Verify inputs
    if not os.path.exists(args.config):
        print(f"ERROR: Config file not found: {args.config}")
        sys.exit(1)
    if not os.path.exists(f"{args.input}.bed"):
        print(f"ERROR: Genotype file not found: {args.input}.bed")
        sys.exit(1)

    # Load config
    config = load_model_config(args.config)
    
    # Build and run command
    cmd = build_plink_command(config, args.input, args.output)
    print(f"Running: {' '.join(cmd)}")
    
    try:
        subprocess.run(cmd, check=True)
    except subprocess.CalledProcessError as e:
        print(f"ERROR: PLINK2 execution failed: {e}")
        sys.exit(1)

    # Post-process to rename OR to Odds_Ratio
    input_file = f"{args.output}.assoc.logistic"
    output_file = f"{args.output}.tsv"
    
    if not os.path.exists(input_file):
        print(f"ERROR: PLINK output not found: {input_file}")
        sys.exit(1)

    with open(input_file, 'r') as infile, open(output_file, 'w') as outfile:
        header = infile.readline().strip().split('\t')
        # Find and rename OR column
        new_header = []
        for col in header:
            if col == 'OR':
                new_header.append('Odds_Ratio')
            else:
                new_header.append(col)
        outfile.write('\t'.join(new_header) + '\n')
        
        for line in infile:
            outfile.write(line)

    print(f"SUCCESS: GWAS results written to {output_file}")

if __name__ == "__main__":
    main()